const emails = $input.all();

// Filter out automated/no-reply messages
const automatedPatterns = [
  /no.?reply/i,
  /noreply/i,
  /donotreply/i,
  /notification/i,
  /automated/i,
  /mailer-daemon/i,
  /postmaster/i,
  /bounce/i,
  /unsubscribe/i,
  /auto-?generated/i
];

const humanReplies = emails.filter(email => {
  const from = email.json.from || '';
  const subject = (email.json.subject || '').toLowerCase();
  const isAutomated = automatedPatterns.some(p => p.test(from) || p.test(subject));
  const isReply = subject.startsWith('re:') || subject.startsWith('fwd:') || email.json.inReplyTo;
  return !isAutomated;
});

return humanReplies.map(email => ({
  json: {
    from: email.json.from,
    subject: email.json.subject,
    snippet: (email.json.text || email.json.html || '').slice(0, 300).replace(/<[^>]+>/g, '').trim(),
    date: email.json.date,
    messageId: email.json.messageId
  }
}));

const fs = require('fs');
const LOG_PATH = '/root/.openclaw/workspace/assets/email-replies.json';

let replies = [];
try { replies = JSON.parse(fs.readFileSync(LOG_PATH, 'utf8')); } catch(e) { replies = []; }

const newReplies = $input.all().map(item => ({
  ...item.json,
  logged_at: new Date().toISOString()
}));

replies.push(...newReplies);

// Keep last 500 entries
if (replies.length > 500) replies = replies.slice(-500);

fs.writeFileSync(LOG_PATH, JSON.stringify(replies, null, 2));
return [{ json: { logged: newReplies.length, total: replies.length } }];
